using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class FlexibleQueryFunction
{
    [FunctionName("FlexibleQueryFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            var parameters = new Dictionary<string, object>();
            var conditions = new List<string>();
            
            foreach (var param in req.Query)
            {
                if (!string.IsNullOrEmpty(param.Value.ToString()))
                {
                    var paramName = param.Key;
                    var paramValue = param.Value.ToString();
                    
                    if (paramName.EndsWith("_min"))
                    {
                        var baseName = paramName.Substring(0, paramName.Length - 4);
                        conditions.Add($"[{baseName}] >= @{baseName}_min");
                        parameters.Add($"@{baseName}_min", paramValue);
                    }
                    else if (paramName.EndsWith("_max"))
                    {
                        var baseName = paramName.Substring(0, paramName.Length - 4);
                        conditions.Add($"[{baseName}] <= @{baseName}_max");
                        parameters.Add($"@{baseName}_max", paramValue);
                    }
                    else if (paramName.EndsWith("_contains"))
                    {
                        var baseName = paramName.Substring(0, paramName.Length - 9);
                        conditions.Add($"[{baseName}] LIKE @{baseName}_contains");
                        parameters.Add($"@{baseName}_contains", $"%{paramValue}%");
                    }
                    else if (paramName.EndsWith("_start"))
                    {
                        var baseName = paramName.Substring(0, paramName.Length - 6);
                        conditions.Add($"[{baseName}] LIKE @{baseName}_start");
                        parameters.Add($"@{baseName}_start", $"{paramValue}%");
                    }
                    else if (paramName.EndsWith("_end"))
                    {
                        var baseName = paramName.Substring(0, paramName.Length - 4);
                        conditions.Add($"[{baseName}] LIKE @{baseName}_end");
                        parameters.Add($"@{baseName}_end", $"%{paramValue}");
                    }
                    else
                    {
                        conditions.Add($"[{paramName}] = @{paramName}");
                        parameters.Add($"@{paramName}", paramValue);
                    }
                }
            }
            
            var whereClause = conditions.Any() ? "WHERE " + string.Join(" AND ", conditions) : "";
            var sqlQuery = $"SELECT * FROM [dbo].[YourTableName] {whereClause}";
            
            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(sqlQuery, connection))
                {
                    foreach (var param in parameters)
                    {
                        command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
                    }
                    
                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var results = new List<Dictionary<string, object>>();
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.GetValue(i) ?? DBNull.Value;
                            }
                            results.Add(row);
                        }
                        return new OkObjectResult(results);
                    }
                }
            }
        }
        catch (Exception ex)
        {
            log.LogError($"Error executing query: {ex.Message}");
            return new StatusCodeResult(500);
        }
